// Minimal deterministic 2048 core logic

export type Tile = number | 0;
export type Board = Tile[]; // length 16, row-major

export type GameState = 'playing' | 'won' | 'lost';

export class RNG {
  seed: number;
  constructor(seed = 1) { this.seed = seed >>> 0; }
  next() {
    // xorshift32
    let x = this.seed || 1;
    x ^= x << 13; x >>>= 0;
    x ^= x >>> 17;
    x ^= x << 5; x >>>= 0;
    this.seed = x;
    return x / 0xFFFFFFFF;
  }
}

export class Game {
  board: Board;
  score: number;
  moves: number;
  state: GameState;
  preset: 'casual'|'spicy';
  undos_left: number;
  max_undos: number;
  rng: RNG;
  lastSpawned: number | null;

  constructor(seed = 1) {
    this.rng = new RNG(seed);
    this.board = new Array(16).fill(0);
    this.score = 0;
    this.moves = 0;
    this.preset = 'casual';
    this.max_undos = 3;
    this.undos_left = this.max_undos;
    this.state = 'playing';
    this.lastSpawned = null;
    // start with two tiles
    this.spawnRandom();
    this.spawnRandom();
  }

  setSeed(n: number) { this.rng = new RNG(n); }

  setPreset(p: 'casual'|'spicy') {
    this.preset = p;
    // spicy lowers undos and increases 4 spawn rate via spawnRandom
    this.max_undos = (p === 'spicy') ? 1 : 3;
    this.undos_left = Math.min(this.undos_left, this.max_undos);
  }

  resetUndos() { this.undos_left = this.max_undos; }

  index(r: number, c: number) { return r * 4 + c; }

  emptyIndices() {
    const res: number[] = [];
    for (let i = 0; i < 16; i++) if (this.board[i] === 0) res.push(i);
    return res;
  }

  spawnRandom() {
    const empties = this.emptyIndices();
    if (empties.length === 0) return null;
    const pick = Math.floor(this.rng.next() * empties.length);
    const idx = empties[pick];
    // preset affects 4 spawn probability
    const fourProb = (this.preset === 'spicy') ? 0.25 : 0.1;
    const v = (this.rng.next() < (1 - fourProb)) ? 2 : 4;
    this.board[idx] = v;
    this.lastSpawned = idx;
    return { idx, v };
  }

  setBoard(b: Board) {
    if (b.length !== 16) throw new Error('board must be length 16');
    this.board = b.slice();
    this.score = 0;
    this.moves = 0;
    this.state = 'playing';
    this.resetUndos();
  }

  cloneBoard() { return this.board.slice(); }

  canMove() {
    if (this.emptyIndices().length > 0) return true;
    // check merges
    for (let r = 0; r < 4; r++) for (let c = 0; c < 4; c++) {
      const v = this.board[this.index(r,c)];
      if (c < 3 && this.board[this.index(r,c+1)] === v) return true;
      if (r < 3 && this.board[this.index(r+1,c)] === v) return true;
    }
    return false;
  }

  move(dir: 'up'|'down'|'left'|'right') {
    if (this.state !== 'playing') return false;
    const before = this.cloneBoard();
    let moved = false;
    let gained = 0;
    // for undo state we capture pre-move board+score
    const preBoard = this.cloneBoard();
    const preScore = this.score;
    const makeLine = (i: number) => [this.board[i], this.board[i+4], this.board[i+8], this.board[i+12]];

    if (dir === 'left' || dir === 'right') {
      for (let r = 0; r < 4; r++) {
        const row = [] as number[];
        for (let c = 0; c < 4; c++) row.push(this.board[this.index(r,c)] as number);
        const orig = row.slice();
        const newRow = this.processLine(row, dir === 'right');
        for (let c = 0; c < 4; c++) this.board[this.index(r,c)] = newRow[c];
        if (!moved && !arraysEqual(orig, newRow)) moved = true;
      }
    } else {
      for (let c = 0; c < 4; c++) {
        const col = [] as number[];
        for (let r = 0; r < 4; r++) col.push(this.board[this.index(r,c)] as number);
        const orig = col.slice();
        const newCol = this.processLine(col, dir === 'down');
        for (let r = 0; r < 4; r++) this.board[this.index(r,c)] = newCol[r];
        if (!moved && !arraysEqual(orig, newCol)) moved = true;
      }
    }

    if (moved) {
      this.moves += 1;
      // spawn after a valid move
      this.spawnRandom();
      // recompute score as sum of board for simplicity of deterministic scoring increments
      // but we will increment gained inside processLine via side-effect
    }

    // if moved, store undo snapshot (we allow undo until used up)
    if (moved) {
      (this as any)._lastUndo = { board: preBoard, score: preScore };
    }
    // check for win (tile 2048) or loss
    if (this.board.some(v => v === 2048)) this.state = 'won';
    else if (!this.canMove()) this.state = 'lost';
    return moved;
  }

  processLine(line: number[], reverse = false) {
    const arr = reverse ? line.slice().reverse() : line.slice();
    const result: number[] = [0,0,0,0];
    let write = 0;
    for (let i = 0; i < 4; i++) {
      const v = arr[i];
      if (v === 0) continue;
      if (write > 0 && result[write-1] === v && result[write-1] !== 0 && (i>0)) {
        // merge with previous
        result[write-1] = result[write-1] * 2;
        this.score += result[write-1];
      } else {
        result[write++] = v;
      }
    }
    while (write < 4) { result[write++] = 0; }
    return reverse ? result.reverse() : result;
  }

  undo() {
    if (!(this as any)._lastUndo) return false;
    if (this.undos_left <= 0) return false;
    const s = (this as any)._lastUndo as {board:number[], score:number};
    this.board = s.board.slice();
    this.score = s.score;
    this.undos_left -= 1;
    this.state = 'playing';
    return true;
  }
}

function arraysEqual(a: number[], b: number[]) {
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) if (a[i] !== b[i]) return false;
  return true;
}

export function renderToText(g: Game) {
  const rows: string[] = [];
  for (let r = 0; r < 4; r++) {
    const row = [] as string[];
    for (let c = 0; c < 4; c++) row.push(String(g.board[g.index(r,c)]).padStart(4, ' '));
    rows.push(row.join(' '));
  }
  const best = Math.max(...g.board);
  return `\n${rows.join('\n')}\nscore: ${g.score}\nmoves: ${g.moves}\nstate: ${g.state}\npreset: ${g.preset}\nundos_left: ${g.undos_left}\nbest: ${best}\n`;
}

import { Game, renderToText } from './game';

// expose deterministic game on window for tests
declare global { interface Window {
  game: any;
  advanceTime(ms:number): void;
  render_game_to_text(): string;
} }

let game = new Game(1);
(window as any).game = game;

// UI state
let reducedMotion = false;
let highContrast = false;

(window as any).setReducedMotion = (v:boolean) => { reducedMotion = v; document.documentElement.classList.toggle('reduced-motion', !!v); };
(window as any).setHighContrast = (v:boolean) => { highContrast = v; document.documentElement.classList.toggle('high-contrast', !!v); };

(window as any).setGameSeed = (s:number) => { ((window as any).game as Game).setSeed(s); };
(window as any).setBoardSeed = (s:number) => { ((window as any).game as Game).setSeed(s); };
(window as any).setPreset = (p:'casual'|'spicy') => { ((window as any).game as Game).setPreset(p); };
(window as any).undo = () => ((window as any).game as Game).undo();
(window as any).setBoard = (b:number[]) => ((window as any).game as Game).setBoard(b);
(window as any).move = (dir:'up'|'down'|'left'|'right') => ((window as any).game as Game).move(dir);
(window as any).render_game_to_text = () => renderToText((window as any).game as Game);
(window as any).advanceTime = (ms:number) => { /* deterministic time progression: no-op but kept for API */ };

// minimal DOM build for polished UI while keeping deterministic hooks
function buildUI() {
  const app = document.getElementById('app')!;
  app.innerHTML = '';
  const controls = document.createElement('div'); controls.className = 'controls';
  controls.innerHTML = `
    <button id="restart" class="btn">Restart</button>
    <label class="tog"> <input id="hc" type="checkbox"> High contrast</label>
    <label class="tog"> <input id="rm" type="checkbox"> Reduced motion</label>
  `;
  app.appendChild(controls);

  const boardWrap = document.createElement('div'); boardWrap.style.position='relative';
  const board = document.createElement('div'); board.className = 'board'; board.id='board';
  // grid background cells
  for (let i=0;i<16;i++){ const c = document.createElement('div'); c.className='cell'; c.dataset.index=String(i); board.appendChild(c); }
  boardWrap.appendChild(board);
  app.appendChild(boardWrap);

  // overlays
  const overlay = document.createElement('div'); overlay.id='overlay'; overlay.style.display='none'; overlay.className='overlay'; boardWrap.appendChild(overlay);

  // hooks
  (document.getElementById('restart')!).addEventListener('click', ()=>{ resetGame(); });
  (document.getElementById('hc') as HTMLInputElement).addEventListener('change', (e)=>{ const v=(e.target as HTMLInputElement).checked; (window as any).setHighContrast(v); });
  (document.getElementById('rm') as HTMLInputElement).addEventListener('change', (e)=>{ const v=(e.target as HTMLInputElement).checked; (window as any).setReducedMotion(v); });

  // touch handlers for swipe (mobile)
  let startX = 0, startY = 0;
  board.addEventListener('touchstart', (ev)=>{ const t = ev.touches[0]; startX = t.clientX; startY = t.clientY; });
  board.addEventListener('touchend', (ev)=>{
    const t = ev.changedTouches[0]; const dx = t.clientX - startX; const dy = t.clientY - startY;
    if (Math.hypot(dx,dy) < 20) return;
    const dir = Math.abs(dx) > Math.abs(dy) ? (dx>0 ? 'right' : 'left') : (dy>0 ? 'down' : 'up');
    const moved = (window as any).move(dir);
    if (moved) render();
  });
}

// initialize UI after DOM ready
if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', ()=>{ buildUI(); render(); });
else { buildUI(); render(); }

function resetGame(){
  // re-create deterministic game with same seed
  (window as any).game = new Game(1);
  // keep reference
  render();
}

// keyboard controls
window.addEventListener('keydown', (e) => {
  const map: Record<string, any> = {
    ArrowUp: 'up', ArrowDown: 'down', ArrowLeft: 'left', ArrowRight: 'right',
    w: 'up', s: 'down', a: 'left', d: 'right'
  };
  const k = (e.key.length ===1) ? e.key.toLowerCase() : e.key;
  const dir = (map as any)[k];
  if (dir) {
    const moved = (window as any).move(dir);
    if (moved) render();
  }
});

function render() {
  // text render preserved for tests
  const out = (window as any).render_game_to_text();
  const el = document.getElementById('render');
  if (el) el.textContent = out;

  // visual render: map tiles to absolute-positioned divs
  const board = document.getElementById('board');
  if (!board) return;
  // clear existing tiles
  const existing = board.querySelectorAll('.tile'); existing.forEach(n=>n.remove());
  const g = (window as any).game as Game;
  for (let i=0;i<16;i++){
    const v = g.board[i]; if (v===0) continue;
    const r = Math.floor(i/4), c = i%4;
    const tile = document.createElement('div'); tile.className='tile'; tile.textContent=String(v);
    // set color based on value (tiny mapping)
    tile.style.left = `${8 + c*(100+8)}px`; tile.style.top = `${8 + r*(100+8)}px`;
    tile.style.width='100px'; tile.style.height='100px';
    tile.style.fontSize = v>=1024? '18px' : '24px';
    tile.style.background = v===2? '#eee4da' : v===4? '#ede0c8' : '#f2b179';
    board.appendChild(tile);
  }

  // overlays on win/loss
  const overlay = document.getElementById('overlay')!;
  if (g.state === 'won') { overlay.style.display='flex'; overlay.innerHTML = `<div>You won!<div><button id="ov-restart" class="btn">Restart</button></div></div>`; (document.getElementById('ov-restart')!).addEventListener('click', resetGame); }
  else if (g.state === 'lost') { overlay.style.display='flex'; overlay.innerHTML = `<div>Game Over<div><button id="ov-restart2" class="btn">Restart</button></div></div>`; (document.getElementById('ov-restart2')!).addEventListener('click', resetGame); }
  else overlay.style.display='none';
}

render();

